mapper.update:
UPDATE spwx_plan_weeks
SET summary=#{summary},
    summary_date=#{summaryDate}
WHERE week_id = #{id}

mapper.select:
select *
from spwx_plan_weeks
where user_id = #{userId}
order by begin_date desc, week_id desc;

select *
from spwx_plan_weeks
where user_id = #{userId}

    and status = #{status}

order by begin_date desc, week_id desc;

select *
from spwx_plan_weeks
where week_id = #{id} and user_id = #{userId};

select *
from spwx_plan_weeks
order by begin_date desc, week_id desc;
